# Configure logging
logging.basicConfig(level=logging.INFO, format='%(asctime)s - %(threadName)s - %(levelname)s - %(message)s')
logger = logging.getLogger(__name__)


class TransactionType(Enum):
    DEPOSIT = "deposit"
    WITHDRAWAL = "withdrawal"
    TRANSFER = "transfer"


class TransactionStatus(Enum):
    PENDING = "pending"
    COMMITTED = "committed"
    ROLLED_BACK = "rolled_back"
    FAILED = "failed"


class InsufficientFundsError(Exception):
    pass


class AccountNotFoundError(Exception):
    pass


class TransactionError(Exception):
    pass


@dataclass
class Transaction:
    transaction_id: str
    transaction_type: TransactionType
    source_account_id: Optional[str]
    destination_account_id: Optional[str]
    amount: float
    status: TransactionStatus = TransactionStatus.PENDING
    timestamp: datetime = field(default_factory=datetime.utcnow)
    description: str = ""


@dataclass
class Account:
    account_id: str
    owner: str
    balance: float = 0.0
    lock: threading.RLock = field(default_factory=threading.RLock)
    transaction_history: list = field(default_factory=list)

    def __repr__(self):
        return f"Account(id={self.account_id}, owner={self.owner}, balance={self.balance:.2f})"


class TransactionManager:
    """Manages financial transactions with proper locking and atomic operations."""

    def __init__(self):
        self._accounts: dict[str, Account] = {}
        self._transactions: dict[str, Transaction] = {}
        self._global_lock = threading.Lock()  # For account creation/deletion
        self._transaction_log_lock = threading.Lock()

    def create_account(self, owner: str, initial_balance: float = 0.0) -> Account:
        """Create a new account with an optional initial balance."""
        if initial_balance < 0:
            raise ValueError("Initial balance cannot be negative")

        with self._global_lock:
            account_id = str(uuid.uuid4())[:8]
            account = Account(account_id=account_id, owner=owner, balance=initial_balance)
            self._accounts[account_id] = account
            logger.info(f"Created account {account_id} for {owner} with balance {initial_balance:.2f}")
            return account

    def get_account(self, account_id: str) -> Account:
        """Retrieve an account by ID."""
        if account_id not in self._accounts:
            raise AccountNotFoundError(f"Account {account_id} not found")
        return self._accounts[account_id]

    def get_balance(self, account_id: str) -> float:
        """Thread-safe balance read."""
        account = self.get_account(account_id)
        with account.lock:
            return account.balance

    @contextmanager
    def _ordered_locks(self, *accounts: Account):
        """
        Acquire locks on multiple accounts in a consistent order (by account_id)
        to prevent deadlocks.
        """
        sorted_accounts = sorted(accounts, key=lambda a: a.account_id)
        locks_acquired = []
        try:
            for account in sorted_accounts:
                account.lock.acquire()
                locks_acquired.append(account.lock)
            yield
        finally:
            for lock in reversed(locks_acquired):
                lock.release()

    def _log_transaction(self, transaction: Transaction):
        """Thread-safe transaction logging."""
        with self._transaction_log_lock:
            self._transactions[transaction.transaction_id] = transaction

    def deposit(self, account_id: str, amount: float, description: str = "") -> Transaction:
        """
        Atomically deposit funds into an account.
        Uses account-level lock for the read-modify-write operation.
        """
        if amount <= 0:
            raise ValueError("Deposit amount must be positive")

        account = self.get_account(account_id)
        transaction = Transaction(
            transaction_id=str(uuid.uuid4())[:12],
            transaction_type=TransactionType.DEPOSIT,
            source_account_id=None,
            destination_account_id=account_id,
            amount=amount,
            description=description or f"Deposit of {amount:.2f}",
        )

        with account.lock:
            try:
                # Atomic read-modify-write
                old_balance = account.balance
                new_balance = old_balance + amount
                account.balance = new_balance
                transaction.status = TransactionStatus.COMMITTED
                account.transaction_history.append(transaction)
                logger.info(
                    f"DEPOSIT: Account {account_id} | "
                    f"{old_balance:.2f} -> {new_balance:.2f} | "
                    f"TxID: {transaction.transaction_id}"
                )
            except Exception as e:
                transaction.status = TransactionStatus.FAILED
                logger.error(f"DEPOSIT FAILED: {e}")
                raise TransactionError(f"Deposit failed: {e}") from e

        self._log_transaction(transaction)
        return transaction

    def withdraw(self, account_id: str, amount: float, description: str = "") -> Transaction:
        """
        Atomically withdraw funds from an account.
        Uses account-level lock and checks for sufficient funds.
        """
        if amount <= 0:
            raise ValueError("Withdrawal amount must be positive")

        account = self.get_account(account_id)
        transaction = Transaction(
            transaction_id=str(uuid.uuid4())[:12],
            transaction_type=TransactionType.WITHDRAWAL,
            source_account_id=account_id,
            destination_account_id=None,
            amount=amount,
            description=description or f"Withdrawal of {amount:.2f}",
        )

        with account.lock:
            try:
                # Atomic read-check-modify-write
                old_balance = account.balance
                if old_balance < amount:
                    transaction.status = TransactionStatus.FAILED
                    self._log_transaction(transaction)
                    raise InsufficientFundsError(
                        f"Account {account_id} has insufficient funds: "
                        f"balance={old_balance:.2f}, requested={amount:.2f}"
                    )
                new_balance = old_balance - amount
                account.balance = new_balance
                transaction.status = TransactionStatus.COMMITTED
                account.transaction_history.append(transaction)
                logger.info(
                    f"WITHDRAWAL: Account {account_id} | "
                    f"{old_balance:.2f} -> {new_balance:.2f} | "
                    f"TxID: {transaction.transaction_id}"
                )
            except InsufficientFundsError:
                raise
            except Exception as e:
                transaction.status = TransactionStatus.FAILED
                logger.error(f"WITHDRAWAL FAILED: {e}")
                raise TransactionError(f"Withdrawal failed: {e}") from e

        self._log_transaction(transaction)
        return transaction

    def transfer(
        self,
        source_account_id: str,
        destination_account_id: str,
        amount: float,
        description: str = "",
    ) -> Transaction:
        """
        Atomically transfer funds between two accounts.
        Acquires locks on both accounts in a consistent order to prevent deadlocks.
        Implements a two-phase approach: validate then commit, with rollback on failure.
        """
        if amount <= 0:
            raise ValueError("Transfer amount must be positive")

        if source_account_id == destination_account_id:
            raise ValueError("Cannot transfer to the same account")

        source = self.get_account(source_account_id)
        destination = self.get_account(destination_account_id)

        transaction = Transaction(
            transaction_id=str(uuid.uuid4())[:12],
            transaction_type=TransactionType.TRANSFER,
            source_account_id=source_account_id,
            destination_account_id=destination_account_id,
            amount=amount,
            description=description or f"Transfer of {amount:.2f} from {source_account_id} to {destination_account_id}",
        )

        # Acquire locks in consistent order to prevent deadlocks
        with self._ordered_locks(source, destination):
            try:
                # Phase 1: Validate
                source_old_balance = source.balance
                if source_old_balance < amount:
                    transaction.status = TransactionStatus.FAILED
                    self._log_transaction(transaction)
                    raise InsufficientFundsError(
                        f"Account {source_account_id} has insufficient funds: "
                        f"balance={source_old_balance:.2f}, requested={amount:.2f}"
                    )

                dest_old_balance = destination.balance

                # Phase 2: Commit (debit source, credit destination)
                source.balance = source_old_balance - amount
                destination.balance = dest_old_balance + amount

                transaction.status = TransactionStatus.COMMITTED
                source.transaction_history.append(transaction)
                destination.transaction_history.append(transaction)

                logger.info(
                    f"TRANSFER: {source_account_id} ({source_old_balance:.2f} -> {source.balance:.2f}) "
                    f"-> {destination_account_id} ({dest_old_balance:.2f} -> {destination.balance:.2f}) | "
                    f"Amount: {amount:.2f} | TxID: {transaction.transaction_id}"
                )

            except InsufficientFundsError:
                raise
            except Exception as e:
                # Rollback: restore original balances
                logger.error(f"TRANSFER FAILED, rolling back: {e}")
                source.balance = source_old_balance
                destination.balance = dest_old_balance
                transaction.status = TransactionStatus.ROLLED_BACK
                self._log_transaction(transaction)
                raise TransactionError(f"Transfer failed and was rolled back: {e}") from e

        self._log_transaction(transaction)
        return transaction

    def get_transaction_history(self, account_id: str) -> list[Transaction]:
        """Get transaction history for an account."""
        account = self.get_account(account_id)
        with account.lock:
            return list(account.transaction_history)

    def get_transaction(self, transaction_id: str) -> Optional[Transaction]:
        """Retrieve a transaction by ID."""
        with self._transaction_log_lock:
            return self._transactions.get(transaction_id)

    def get_all_accounts_summary(self) -> dict[str, dict]:
        """Get a summary of all accounts (thread-safe snapshot)."""
        with self._global_lock:
            summary = {}
            for account_id, account in self._accounts.items():
                with account.lock:
                    summary[account_id] = {
                        "owner": account.owner,
                        "balance": account.balance,
                        "num_transactions": len(account.transaction_history),
                    }
            return summary


def process_financial_transactions(transactions_data: list[dict], manager: TransactionManager) -> list[Transaction]:
    """
    Process a batch of financial transactions.
    Each transaction_data dict should have:
        - type: "deposit", "withdrawal", or "transfer"
        - amount: float
        - account_id: str (for deposit/withdrawal)
        - source_account_id: str (for transfer)
        - destination_account_id: str (for transfer)
        - description: str (optional)
    """
    results = []
    for tx_data in transactions_data:
        tx_type = tx_data.get("type")
        amount = tx_data.get("amount", 0)
        description = tx_data.get("description", "")

        try:
            if tx_type == "deposit":
                result = manager.deposit(tx_data["account_id"], amount, description)
            elif tx_type == "withdrawal":
                result = manager.withdraw(tx_data["account_id"], amount, description)
            elif tx_type == "transfer":
                result = manager.transfer(
                    tx_data["source_account_id"],
                    tx_data["destination_account_id"],
                    amount,
                    description,
                )
            else:
                logger.error(f"Unknown transaction type: {tx_type}")
                continue
            results.append(result)
        except (InsufficientFundsError, AccountNotFoundError, ValueError, TransactionError) as e:
            logger.warning(f"Transaction failed: {e}")

    return results


def run_concurrent_stress_test(manager: TransactionManager, accounts: list[Account]):
    """Run concurrent transactions to stress-test the locking mechanism."""
    import random

    errors = []

    def worker(worker_id: int, num_operations: int):
        for i in range(num_operations):
            try:
                op = random.choice(["deposit", "withdrawal", "transfer"])
                if op == "deposit":
                    acc = random.choice(accounts)
                    amount = round(random.uniform(1, 100), 2)
                    manager.deposit(acc.account_id, amount, f"Worker {worker_id} deposit #{i}")
                elif op == "withdrawal":
                    acc = random.choice(accounts)
                    amount = round(random.uniform(1, 50), 2)
                    try:
                        manager.withdraw(acc.account_id, amount, f"Worker {worker_id} withdrawal #{i}")
                    except InsufficientFundsError:
                        pass  # Expected in concurrent scenario
                elif op == "transfer":
                    src, dst = random.sample(accounts, 2)
                    amount = round(random.uniform(1, 30), 2)
                    try:
                        manager.transfer(
                            src.account_id, dst.account_id, amount,
                            f"Worker {worker_id} transfer #{i}"
                        )
                    except InsufficientFundsError:
                        pass  # Expected
            except Exception as e:
                errors.append(e)
                logger.error(f"Worker {worker_id} unexpected error: {e}")

    # Calculate initial total balance
    initial_total = sum(manager.get_balance(acc.account_id) for acc in accounts)
    logger.info(f"Initial total balance across all accounts: {initial_total:.2f}")

    # Launch concurrent workers
    num_workers = 8
    ops_per_worker = 50
    threads = []
    for w in range(num_workers):
        t = threading.Thread(target=worker, args=(w, ops_per_worker), name=f"Worker-{w}")
        threads.append(t)

    for t in threads:
        t.start()
    for t in threads:
        t.join()

    # Verify invariant: total balance should be conserved
    # (deposits and withdrawals change total, but transfers don't)
    final_total = sum(manager.get_balance(acc.account_id) for acc in accounts)
    logger.info(f"Final total balance across all accounts: {final_total:.2f}")
    logger.info(f"Errors encountered: {len(errors)}")

    return initial_total, final_total, errors


